"""
内部算法参数默认配置
此文件不面向终端用户, 用于 CC 根据实际执行和资源情况进行调整
"""

# ============ LightGBM 默认参数 ============
# 用于 summary 基线模型训练(验证特征集效果)
# 这些参数控制 LightGBM 的模型复杂度和正则化强度
DEFAULT_LGB_PARAMS = {
    'objective': 'binary',       # 目标函数, 二分类任务固定为 binary
    'boosting': 'gbdt',          # 提升方法, gbdt 为梯度提升决策树; 可选 'dart'(更慢但可能更准)、'goss'(更快)
    'learning_rate': 0.05,       # 学习率, 范围(0,1]. 越小收敛越慢但泛化更好, 需配合增大 num_boost_round; 常用 0.01~0.1
    'num_leaves': 31,            # 叶子节点数, 控制模型复杂度. 越大拟合能力越强但越容易过拟合; 建议 15~127, 不超过 2^max_depth
    'max_depth': 5,              # 树的最大深度, 限制模型复杂度. -1 表示不限制; 越大模型越复杂, 建议 3~8
    'min_child_samples': 100,    # 叶子节点最小样本数, 防止过拟合. 越大越保守; 小数据集可降至 20~50, 大数据集可提至 200+
    'subsample': 0.7,            # 行采样比例, 范围(0,1]. 每棵树随机采样训练数据的比例; 越小随机性越大, 防过拟合但可能欠拟合
    'colsample_bytree': 0.7,     # 列采样比例, 范围(0,1]. 每棵树随机采样特征的比例; 特征多时可降至 0.5, 特征少时可提至 0.9
    'reg_alpha': 0.1,            # L1 正则化系数, >=0. 越大越倾向于稀疏(更多特征权重为0); 常用 0~1
    'reg_lambda': 1.0,           # L2 正则化系数, >=0. 越大对权重惩罚越重, 防过拟合; 常用 0~10
    'verbose': -1,               # 日志级别, -1 静默; 调试时可设为 0 或 1
}

# ============ LightGBM 筛选专用参数 ============
# 用于 d03-d06 重要性筛选阶段
# 与 DEFAULT_LGB_PARAMS 的关键区别: 不做行列采样(subsample=1.0, colsample_bytree=1.0)
# 原因: 筛选阶段的目标是准确评估每个特征的真实贡献, 需要确保每个特征在每棵树中都被评估
# 如果 colsample_bytree<1.0, 某些特征可能因为随机未被采样而重要性被低估, 导致误剔除
SCREENING_LGB_PARAMS = {
    'objective': 'binary',
    'boosting': 'gbdt',
    'learning_rate': 0.05,
    'num_leaves': 31,
    'max_depth': 5,
    'min_child_samples': 100,
    'subsample': 1.0,            # 筛选阶段不做行采样, 使用全部数据评估特征
    'colsample_bytree': 1.0,     # 筛选阶段不做列采样, 确保每个特征在每棵树中都被评估
    'reg_alpha': 0.1,
    'reg_lambda': 1.0,
    'verbose': -1,
}

# ============ d01 toad 初筛参数 ============
D01_PARAMS = {
    # 抽样数上限: 从样本表中随机抽样的最大记录数
    # 越大数据越全面但 SQL 执行时间和内存占用越高; 样本量不足时自动取全量
    # 建议范围: 1000000~5000000, 根据集群资源调整
    'random_num': 3000000,

    # 抽样随机种子: None 表示每次随机生成(不可复现), 设为固定整数可复现结果
    # 调试阶段建议设固定值(如 42), 正式运行可设 None
    'random_seed': None,

    # 每轮处理的特征个数上限: toad 筛选时分批处理特征, 每批最多处理的特征数
    # 越大单次 SQL 查询的列越多, 内存压力越大; 越小则需要更多轮次, 总耗时增加
    # 建议范围: 200~1000, 特征总数少时可设大些
    'round_num': 500,

    # 最大迭代轮数: None=不限制(按原逻辑收敛即停), 正整数=最多迭代N轮
    # 多轮迭代主要收敛相关性筛选(corr在分组内计算), iv和empty第一轮即完成
    # 特征质量高时设1即可跳过无意义的后续迭代; 建议范围: 1~5 或 None
    'max_round': None,

    # 筛选引擎选择: None=自动检测(有toad用toad，无toad降级native), True=强制native, False=强制toad(无toad则报错)
    # 建议生产环境保持 None; 环境无 toad 包时设 True 可跳过检测直接使用内置实现
    'use_native': None,
}

# ============ d01 merge 参数 ============
D01_MERGE_PARAMS = {
    # 单个 merge 表的最大特征数: 合并宽表时每张 merge 表最多包含的特征列数
    # MaxCompute 单表列数有上限, 且列过多会影响查询性能; 越小则需要更多 merge 表
    # 建议范围: 500~1000
    'max_fea_num': 800,

    # 最大 merge 表数量: 限制生成的 merge 表总数
    # merge 表过多会导致后续步骤 join 次数增多, 影响查询效率
    # 建议范围: 5~20
    'max_table_num': 10,
}

# ============ d02 PSI 筛选参数 ============
D02_PARAMS = {
    # 抽样数上限: PSI 计算需要 DEV 和各 OOT 期的数据, 每期最多抽样的记录数
    # PSI 对样本量要求比 toad 高(需要分箱统计), 建议比 d01 的 random_num 更大
    # 越大 PSI 计算越精准但 SQL 和内存开销越大; 建议范围: 2000000~10000000
    'random_num': 5000000,

    # 抽样随机种子: 同 d01, None 表示随机, 固定整数可复现
    'random_seed': None,

    # exp_period范围: True=仅取dev之后的period(常用), False=取所有非dev的period(含dev之前的历史period)
    'exp_after_dev_only': True,
}

# ============ d03-d06 重要性筛选参数 ============
D03_D06_PARAMS = {
    # LightGBM 训练轮数: d03-d06 各步骤训练模型时的最大迭代次数
    # 越大模型越充分但训练时间越长; d04 需要训练 real_round+null_round 个模型, 此值影响总耗时
    # 建议范围: 500~2000, 特征多/样本大时可适当减小以加速
    'num_boost_round': 1000,

    # === d03 随机重要性筛选 ===
    # 原理: 注入随机噪声特征后训练模型, 重要性低于随机特征的真实特征被认为无用
    # 多轮 bagging 后取剔除特征的并集

    # bagging 轮数: 用不同采样子集重复训练的次数, 结果取并集
    # 越大结果越稳定但耗时线性增长; 建议 3~10
    'd03_bagging_round': 5,

    # bagging 采样比例: 每轮使用的数据比例, 范围(0,1]
    # 越小每轮数据越少、随机性越大; 建议 0.3~0.8
    'd03_bagging_fraction': 0.5,

    # 累计重要性剔除阈值: 将特征按重要性排序, 累计重要性超过此阈值的尾部特征被剔除
    # 值越大(接近1.0)剔除越少越保守, 越小剔除越激进; 建议 0.9~0.99
    'd03_thresholds': 0.95,

    # === d04 null importance 筛选 ===
    # 原理: 对比真实标签训练和打乱标签训练(null)的特征重要性分布
    # 如果某特征在 null 模型中重要性也很高, 说明其贡献是噪声

    # 真实训练轮数: 用真实标签训练模型的次数, 取重要性均值
    # 越大真实重要性估计越稳定; 建议 3~10
    'd04_real_round': 3,

    # 空值训练轮数: 打乱标签训练模型的次数, 构建 null 重要性分布
    # 越大 null 分布越准确, 但耗时线性增长(每轮都要完整训练一次); 建议 10~100
    'd04_null_round': 10,

    # null importance 百分位阈值列表: 遍历多个百分位截断点(split*gain 组合), 选择 OOS AUC 不下降的最大剔除组合
    # 每个值表示百分位数, 如 10 表示剔除 null_score 低于 10th 分位的特征
    # 值越大剔除越多; 列表越长搜索越全面但训练次数=len(split)*len(gain)
    'd04_thresholds_list': [10, 20, 30, 40, 50],

    # === d05 top importance 筛选 ===
    # 原理: 按特征累计重要性(gain)占比截断, 只保留累计贡献在阈值内的 top 特征
    # 遍历多个阈值, 选择 OOS AUC 不下降(gap容忍内)的最精简方案

    # 累计重要性占比阈值列表: 如 0.5 表示只保留累计重要性前 50% 的特征
    # 值越小保留越少越激进; 列表越长搜索越细, 每个阈值需训练一个模型
    # 建议范围: 每个值在 [0.3, 0.95] 之间
    'd05_thresholds_list': [0.5, 0.6, 0.7, 0.8, 0.9],

    # === d06 SHAP importance 筛选 ===
    # 原理: 用 TreeExplainer 计算 SHAP 值, 按 mean(|SHAP|) 累计占比截断
    # 比 gain importance 更准确但计算更慢(需要遍历所有样本)

    # 累计 SHAP 重要性占比阈值列表: 含义同 d05, 但基于 SHAP 值而非 gain
    # SHAP 计算较慢, 阈值列表不宜过长; 建议范围同 d05
    'd06_thresholds_list': [0.5, 0.6, 0.7, 0.8, 0.9],

    # INS 抽样数上限: d03 只用 INS, d04/d05/d06 用 INS 训练
    # 建议范围: 2000000~5000000
    'ins_random_num': 3000000,

    # OOS 抽样数上限: d04/d05/d06 用 OOS 评估
    # OOS 只做预测评估, 不需要太大; 建议范围: 500000~2000000
    'oos_random_num': 1000000,

    # 抽样随机种子: None 表示每次随机生成(不可复现), 设为固定整数可复现结果
    # 调试阶段建议设固定值(如 42), 正式运行可设 None
    'random_seed': None,
}

# ============ d07-d08 WOE 筛选参数 ============
D07_D08_PARAMS = {
    # === d07 WOE 趋势稳定性筛选 ===
    # 原理: 比较 DEV 和 OOT 窗口的 WOE 趋势, 用三个互补指标检测不稳定特征
    # concordance 检测趋势反转, range_ratio 检测区分力丧失, spearman 综合秩相关

    # 一致性比率阈值: 基于所有 bin 对的 WOE 相对顺序一致性, 范围 [0,1]
    # 低于此值认为 OOT 趋势反转(WOE 排序倒挂); 越高越严格, 剔除越多
    # 0.5 表示随机水平, 建议 0.5~0.8
    'd07_concordance_threshold': 0.6,

    # WOE 范围比阈值: OOT 的 WOE 极差 / DEV 的 WOE 极差, 范围 [0,+inf)
    # 低于此值认为 OOT 区分力消失(WOE 变得扁平); 越高越严格
    # 建议 0.1~0.5, 过高会误杀轻微波动的稳定特征
    'd07_range_ratio_threshold': 0.1,

    # Spearman 秩相关系数阈值: DEV 与 OOT 的 WOE 序列秩相关, 范围 [-1,1]
    # 低于此值认为趋势不一致; 越高越严格
    # 建议 0.2~0.6, 分箱数少时(如5箱)秩相关波动较大, 不宜设太高
    'd07_spearman_threshold': 0.2,

    # 最小分组占比阈值: WOE 趋势比较时, 某分箱样本占比低于此值则不参与计算
    # 避免小样本箱的 WOE 波动导致误判; 越大过滤越多箱, 建议 0.005~0.05
    'd07_min_cnt_pct': 0.01,

    # 多窗口策略: True=任一 OOT 窗口不通过就剔除(严格), False=所有 OOT 窗口都不通过才剔除(宽松)
    # OOT 窗口多时建议 False 避免过度剔除; 窗口少(1-2个)时建议 True
    'd07_require_all_windows': True,

    # WOE 分箱方法: 'quantile'(等频分箱) 或 'step'(等距分箱)
    # 等频分箱对异常值更鲁棒, 推荐默认使用 'quantile'
    'woe_method': 'quantile',

    # WOE 分箱数: 分箱数量, 影响 WOE 趋势的粒度
    # 越多趋势越细腻但每箱样本越少、指标波动越大; 建议 4~8
    'woe_num_nbins': 5,

    # 抽样数上限: 从样本表中随机抽样的最大记录数, 在 SQL 取数时完成抽样
    # WOE 分箱计算对样本量要求较高, 建议与 d03-d06 保持一致或更大
    # 建议范围: 2000000~10000000, 根据集群资源调整
    'random_num': 5000000,

    # 抽样随机种子: None 表示每次随机生成(不可复现), 设为固定整数可复现结果
    # 调试阶段建议设固定值(如 42), 正式运行可设 None
    'random_seed': None,
}

# ============ Summary 汇总参数 ============
SUMMARY_PARAMS = {
    # 基线模型训练轮数: summary 阶段用最终特征集训练验证模型的迭代次数
    # 仅用于验证特征集效果, 不需要太大; 越大越精确但越慢
    # 建议 200~500, 与 d03-d06 的 num_boost_round 独立
    'num_boost_round': 300,

    # 评分分布分箱数: 生成评分分布图时的分箱数
    # 越多分布越细致; 建议 5~20
    'score_num_nbins': 10,

    # 抽样数上限: 从样本表中随机抽样的最大记录数, 在 SQL 取数时完成抽样
    # summary 阶段用最终特征集训练验证模型, 数据量适中即可
    # 建议范围: 2000000~10000000, 根据集群资源调整
    'random_num': 5000000,

    # 抽样随机种子: None 表示每次随机生成(不可复现), 设为固定整数可复现结果
    # 调试阶段建议设固定值(如 42), 正式运行可设 None
    'random_seed': None,
}
